import uCharts from '@/components/u-charts/u-charts.js';
import wPicker from '@/components/w-picker/w-picker.vue';
import liChoose from '@/components/li-choose/li-choose.vue';
import { isJSON } from '@/common/checker.js';
var _self;
var canvaPie = null;
export default {
	components: {
		wPicker,
		liChoose
	},
	data() {
		return {
			moreData: '加载更多数据...',
			mode: false,
			showCustomer: false,
			scrollLeft: 0,
			TabCur: -1,
			tidMask: false,
			stateMask: false,
			overTypeMask: false,
			sortMask: false,
			pixelRatio: 1,
			textarea: '',
			total: 0,
			customerList: [],
			rangeDval: ['2017-10-30', '2019-12-31'],
			requestData: {
				over_type: '', //按客户房号、名称和电话关键字进行查询
				type: 3, //按客户归属查询（1我负责的，2共享给我的，3全部客户，4客户共池）
				keyword: '', //搜索
				sort: '', //进行排序（1：按创建时间正叙，2：按创建时间倒叙）
				pid: '', //	按项目进行查询
				state: '', //是否超期（1未成交，2已排号，3已认购，4已网签，5新增）
				page: 1
			},
			allProject: [],
			overTypeData: [
				//全部来源
				{ value: '1', name: '全部来源', checked: true },
				{ value: '2', name: '手动录入', checked: false },
				{ value: '3', name: '人脸识别', checked: false },
				{ value: '4', name: '微信扫码', checked: false }
			],
			tidData: [
				//	客户
				{ value: '3', name: '全部客户', checked: true },
				{ value: '1', name: '我负责的', checked: false },
				{ value: '2', name: '共享给我', checked: false },
				{ value: '4', name: '公池客户', checked: false }
			],
			sortData: [
				//进行排序
				{ value: '1', name: '录入正序', checked: true },
				{ value: '2', name: '录入倒序', checked: false },
				{ value: '3', name: '跟进正序', checked: false },
				{ value: '4', name: '跟进倒序', checked: false }
			],
			stateData: [
				//是否成交
				{ value: '0', name: '全部', checked: true },
				{ value: '1', name: '未成交', checked: false },
				{ value: '2', name: '已排号', checked: false },
				{ value: '3', name: '已认购', checked: false }
			],
			tidIndex: 0,
			stateIndex: 0,
			sortIndex: 0,
			overTypeIndex: 0,
			per_page: 0, //一页多少条数据；
			current_page: 1, //当前页数；
			last_page: 0 ,//一共多少页；
			status: 'more',
			contentText: {
				contentdown: '上拉加载更多',
				contentrefresh: '加载中',
				contentnomore: '没有更多'
			},
			p:1
		};
	},
	onShow() {
		if(this.types){
			this.requestData.type = 1;
			this.tidIndex = 1;
			this.customerList = [];
			this.scrollLeft = 0;
			this.getProject();
		}
	},
	onReachBottom(){
		if (this.current_page < this.last_page) {
			this.current_page = this.current_page + 1;
			this.requestData.page = this.current_page;
			this.getCustomerList();
		}
	},
	onPageScroll(e) {
		if(Math.ceil(e.scrollTop / 1000) == 0){
			this.p = 1
		}else{
			this.p =  Math.ceil(e.scrollTop / 1000);
		}
	},
	onLoad() {
		_self = this;
		this.requestData.over_type = this.overTypeData[this.overTypeIndex].value;
		this.getProject();
		this.getBigareacustomapi();
	},
	
	computed:{
		types(){
			return this.$store.state.customerType;
		}
	},
	methods: {
		getBigareacustomapi() {
			this.$api.customGetbigareacustomapi({}, res => {
				res.data.forEach(res => {
					res.project.forEach(resp => {
						resp.isactive = false;
					});
				});
				this.$store.commit('setSearchPro', res.data);
			});
		},
		toTop() {
			uni.pageScrollTo({
				scrollTop: 0,
				duration: 300
			});
		},
		addCustomer(){
			uni.navigateTo({
				url:'/pages/customer/customer_add'
			})
		},
		cName(name) {
			return this.$tools.cName(name);
		},
		showType(type){
			switch (type) {
				case 'tid':
					this.tidMask = !this.tidMask;
					this.stateMask = false;
					this.sortMask = false;
					this.overTypeMask = false;
					break;
				case 'sort':
					this.sortMask = !this.sortMask;
					this.tidMask = false;
					this.stateMask = false;
					this.overTypeMask = false;
					break;
				case 'state':
					this.stateMask = !this.stateMask;
					this.tidMask = false;
					this.sortMask = false;
					this.overTypeMask = false;
					break;
				case 'overType':
					this.overTypeMask = !this.overTypeMask;
					this.tidMask = false;
					this.stateMask = false;
					this.sortMask = false;
					break;
				default:
					break;
			}
		},
		chooseType(type, index) {
			this.customerList = [];
			this.requestData.page = 1;
			switch (type) {
				case 'tid':
					this.tidIndex = index;
					this.tidMask = !this.tidMask;
					this.requestData.type = this.tidData[this.tidIndex].value;
					this.getCustomerList();
					break;
				case 'sort':
					this.sortIndex = index;
					this.sortMask = !this.sortMask;
					this.requestData.sort = this.sortData[this.sortIndex].value;
					this.getCustomerList();
					break;
				case 'state':
					this.stateIndex = index;
					this.stateMask = !this.stateMask;
					this.requestData.state = this.stateData[this.stateIndex].value;
					this.getCustomerList();
					break;
				case 'overType':
					this.overTypeIndex = index;
					this.overTypeMask = !this.overTypeMask;
					this.requestData.over_type = this.overTypeData[this.overTypeIndex].value;
					this.getCustomerList();
					break;
				default:
					break;
			}
		},
		//选择全部项目
		checkAll() {
			this.TabCur = -1;
			let datas = [];
			this.allProject.forEach(res => {
				datas.push(res.p_id);
			});
			this.pid = this.$tools.toStrings(datas);
			this.requestData.pid = '';
			this.customerList = [];
			this.getCustomerList();
		},
		//获取所有项目
		getProject() {
			uni.showLoading({
				title: '正在加载数据...'
			});
			this.$api.customGetprojectlistcustomapi({}, res => {
				this.allProject = res.data;
				//项目默认全部选中
				this.checkAll();
				//客户管理列表
				// this.getCustomerList();
			});
		},
		detail(items) {
			uni.navigateTo({
				url: '/pages/customer/customer_detail?id=' + items.id
			});
		},
		InputFocus() {
			this.customerList = [];
			this.getCustomerList();
		},
		InputBlur() {
			this.customerList = [];
			this.getCustomerList();
		},
		confirms(data) {
			this.requestData.pid = this.$tools.toStrings(data.pid);
			this.getCustomerList();
		},
		toggleTab(str) {
			this.$refs[str].show();
		},
		onConfirm(val) {
			//如果页面需要调用多个mode类型，可以根据mode处理结果渲染到哪里;
			// switch(this.mode){
			// 	case "date":
			// 		break;
			// }
			this.resultInfo = { ...val };
		},
		chooseProject() {
			this.$refs.lichoose.show();
		},
		checkboxChange(e) {
			var items = this.items;
			let values = e.detail.value;
			for (var i = 0, lenI = items.length; i < lenI; ++i) {
				items[i].checked = false;
				for (var j = 0, lenJ = values.length; j < lenJ; ++j) {
					if (items[i].value == values[j]) {
						items[i].checked = true;
						break;
					}
				}
			}
		},
		//选择单个项目
		tabSelect(item, index) {
			this.TabCur = index;
			this.singleCharts = [];
			this.scrollLeft = (index - 1) * 100;
			this.requestData.pid = item.p_id;
			this.customerList = [];
			this.getCustomerList();
		},
		getCustomerList() {
			uni.showLoading({
				title: '正在加载数据...'
			});
			this.$api.getIndexcustomapi(this.requestData, res => {
				res.data.data.forEach(resp => {
					this.customerList.push(resp);
				});
				this.per_page = res.data.per_page; //一页多少条数据；
				this.current_page = res.data.current_page; //当前页数；
				this.last_page = res.data.last_page; //一共多少页；
				this.total = res.data.total; //总条数
			});
		}
	}
};
